270	- (void)viewDidLoad {
271	    [super viewDidLoad];
272	    self.view.backgroundColor = [UIColor xp_baseBackgroundColor];
273	    
274	    [self addBleConnectStateObserver];
275	    
276	    [self.class markResumeFromRestart:NO];
277	    
278	    self.carInfo = CTMediator.defaultCarInfo;
279	    if(!(self.carInfo.hasBleAbility && !self.carInfo.carFunction.WITHOUT_BLE)){
280	        DLogTagInfo(kBLEKeyTag, @"车辆不支持蓝牙钥匙");
281	        [XPToast showMessage:@"当前车辆不支持手机钥匙"];
282	        [self.navigationController popViewControllerAnimated:YES];
283	        return;
284	    }
285	    
286	    self.bleCheckManager = [XPVehicleExt createBleCheckManager:XPVehicleSDK.shared.vehicleManager.currentVehicle];
287	    
288	    @weakify(self);
289	    [self.rac_deallocDisposable addDisposable:[CTMediator.defaultCarSwitchedSignal.deliverOnMainThread subscribeNext:^(MyCarInfo * _Nullable x) {
290	        @strongify(self);
291	        if(![x.vin isEqualToString:self.carInfo.vin]){
292	            [XPToast showMessage:@"车辆切换，退出检查"];
293	            [self.navigationController popViewControllerAnimated:YES];
294	        }
295	    }]];
296	    
297	    [self.rac_deallocDisposable addDisposable:[self.checkingView.finalSubject subscribeNext:^(id _Nullable x) {
298	        @strongify(self);
299	        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_EMERGENCY_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
300	        [self popToWifiViewController];
301	    }]];
302	    
303	    [self.rac_deallocDisposable addDisposable:[self.checkingView.callSubject subscribeNext:^(id _Nullable x) {
304	        @strongify(self);
305	        [self contactCustomerService];
306	    }]];
307	    
308	    [self.rac_deallocDisposable addDisposable:[[self.checkingView.stopButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
309	        @strongify(self);
310	        [self.navigationController popViewControllerAnimated:YES];
311	    }]];
312	    
313	    [self.rac_deallocDisposable addDisposable:[[self.successView.backButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
314	        @strongify(self);
315	        [self.navigationController popViewControllerAnimated:YES];
316	    }]];
317	    
318	    [self.rac_deallocDisposable addDisposable:[self.failView.finalSubject subscribeNext:^(id _Nullable x) {
319	        @strongify(self);
320	        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_EMERGENCY_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
321	        [self popToWifiViewController];
322	    }]];
323	    
324	    [self.rac_deallocDisposable addDisposable:[self.failView.callSubject subscribeNext:^(id _Nullable x) {
325	        @strongify(self);
326	        [self contactCustomerService];
327	    }]];
328	    
329	    [self.rac_deallocDisposable addDisposable:[[self.failView.nextButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
330	        @strongify(self);
331	        switch (self.currentError.code) {
332	            case XPKeyCheckErrorCodePoweredOff:
333	            {
334	                if([self isPoweredOn]){
335	                    [self restartCheck];
336	                }else{
337	                    XPBleGuideViewController *vc = [XPBleGuideViewController new];
338	                    [vc showInViewController:self];
339	                }
340	            }
341	                break;
342	            case XPKeyCheckErrorCodeNoPermission:
343	            {
344	                NSURL *url = [NSURL URLWithString:UIApplicationOpenSettingsURLString];
345	                if([UIApplication.sharedApplication canOpenURL:url]) [UIApplication.sharedApplication openURL:url options:@{} completionHandler:^(BOOL success) {}];
346	            }
347	                break;
348	            default:
349	                [self restartCheck];
350	                break;
351	        }
352	    }]];
353	    
354	    [self.rac_deallocDisposable addDisposable:[[self.failView.backButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
355	        @strongify(self);
356	        [self.navigationController popViewControllerAnimated:YES];
357	    }]];
358	    
359	    [self.rac_deallocDisposable addDisposable:[self.finalView.finalSubject subscribeNext:^(id _Nullable x) {
360	        @strongify(self);
361	        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_EMERGENCY_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
362	        [self popToWifiViewController];
363	    }]];
364	    
365	    [self.rac_deallocDisposable addDisposable:[self.finalView.callSubject subscribeNext:^(id _Nullable x) {
366	        @strongify(self);
367	        [self contactCustomerService];
368	    }]];
369	    
370	    [self.rac_deallocDisposable addDisposable:[[self.finalView.backButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
371	        @strongify(self);
372	        [self.navigationController popViewControllerAnimated:YES];
373	    }]];
374	    
375	    [self.rac_deallocDisposable addDisposable:[[self.finalView.nextButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
376	        @strongify(self);
377	        if([self wifiKeySupported]){
378	            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_TRY_EMERGENCY_KEY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
379	            [self popToWifiViewController];
380	        }else{
381	            [self restartCheck];
382	        }
383	    }]];
384	    
385	    if(![self.params[@"resume"] boolValue]){
386	        [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_ENTRY module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId), @"from": @(self.from)}];
387	    }
388	    
389	    //如果数字钥匙3.0，开通了钱包钥匙,那就不归App控制了
390	    if ([XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager vaildBleKeyCategory] == XPDigitalKeyCategoryPHONE_UWB_KEY) {
391	        [QMUIAlertController showAlertWithTitle:@"如遇手机钥匙无法连接车辆，请查看钥匙状态是否正常"
392	                                        message:@""
393	                               leftButtionTitle:@"关闭"
394	                                 leftButtonType:QMUIAlertActionStyleCancel
395	                                     leftAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
396	            @strongify(self);
397	            [self.navigationController popViewControllerAnimated:YES];
398	        }
399	                               rightButtonTitle:@"查看钥匙状态"
400	                                rightButtonType:QMUIAlertActionStyleDefault
401	                                    rightAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
402	            [XPCarKeyHelp.shared openCarKeyPass];
403	            [self.navigationController popViewControllerAnimated:YES];
404	        }];
405	        return;
406	    }
407	    
408	    [self startCheck];
409	}
