420	- (void)restartCheck{
421	    NSMutableDictionary *params = self.params.mutableCopy;
422	    params[@"resume"] = @NO;
423	    self.params = [NSDictionary dictionaryWithDictionary:params];
424	    [self startCheck];
425	}
426	    
427	- (void)startCheck{
428	    @weakify(self);
429	    [[self.checkCommand execute:self.params?:@{}].deliverOnMainThread subscribeNext:^(NSNumber * _Nullable x) {
430	        @strongify(self);
431	        [self updateView];
432	        self.checkingView.hidden = NO;
433	        self.successView.hidden = YES;
434	        self.failView.hidden = YES;
435	        self.finalView.hidden = YES;
436	        
437	        XPKeyCheckProgress progress = [x integerValue];
438	        switch (progress) {
439	            case XPKeyCheckProgressDefault:
440	                self.items = [NSMutableArray new];
441	                break;
442	            case XPKeyCheckProgressCreateKeyChecking:
443	                [self makeItemCheckingWithType:XPKeyCheckingCellTypeCreateKey];
444	                break;
445	            case XPKeyCheckProgressCreateKeyChecked:
446	                [self makeItemSuccessWithType:XPKeyCheckingCellTypeCreateKey];
447	                break;
448	            case XPKeyCheckProgressBleStateChecking:
449	                [self makeItemCheckingWithType:XPKeyCheckingCellTypeBleState];
450	                break;
451	            case XPKeyCheckProgressBleStateChecked:
452	                [self makeItemSuccessWithType:XPKeyCheckingCellTypeBleState];
453	                break;
454	            case XPKeyCheckProgressNearbyChecking:
455	                [self makeItemCheckingWithType:XPKeyCheckingCellTypeNearby];
456	                break;
457	            case XPKeyCheckProgressNearbyChecked:
458	                [self makeItemSuccessWithType:XPKeyCheckingCellTypeNearby];
459	                break;
460	            case XPKeyCheckProgressResetBleChecking:
461	                [self makeItemCheckingWithType:XPKeyCheckingCellTypeResetBle];
462	                break;
463	            case XPKeyCheckProgressResetBleChecked:
464	                [self makeItemSuccessWithType:XPKeyCheckingCellTypeResetBle];
465	                break;
466	            case XPKeyCheckProgressRestartChecking:
467	                [self makeItemCheckingWithType:XPKeyCheckingCellTypeRestart];
468	                break;
469	            case XPKeyCheckProgressRestartChecked:
470	                [self makeItemSuccessWithType:XPKeyCheckingCellTypeRestart];
471	                break;
472	            case XPKeyCheckProgressConnectChecking:
473	                [self makeItemCheckingWithType:XPKeyCheckingCellTypeConnect];
474	                break;
475	            case XPKeyCheckProgressConnectChecked:
476	                [self makeItemSuccessWithType:XPKeyCheckingCellTypeConnect];
477	                break;
478	            case XPKeyCheckProgressCommandChecking:
479	                if(self.command == XPTBoxCommandUnlock){
480	                    if(self.isStart){
481	                        [self makeItemCheckingWithType:XPKeyCheckingCellTypeStart];
482	                    }else{
483	                        [self makeItemCheckingWithType:XPKeyCheckingCellTypeUnlock];
484	                    }
485	                }else{
486	                    [self makeItemCheckingWithType:XPKeyCheckingCellTypeLock];
487	                }
488	                break;
489	            case XPKeyCheckProgressCommandChecked:
490	                if(self.command == XPTBoxCommandUnlock){
491	                    if(self.isStart){
492	                        [self makeItemSuccessWithType:XPKeyCheckingCellTypeStart];
493	                    }else{
494	                        [self makeItemSuccessWithType:XPKeyCheckingCellTypeUnlock];
495	                    }
496	                }else{
497	                    [self makeItemSuccessWithType:XPKeyCheckingCellTypeLock];
498	                }
499	                break;
500	            case XPKeyCheckProgressResetKeyChecking:
501	                [self makeItemCheckingWithType:XPKeyCheckingCellTypeResetKey];
502	                break;
503	            case XPKeyCheckProgressResetKeyChecked:
504	                [self makeItemSuccessWithType:XPKeyCheckingCellTypeResetKey];
505	                break;
506	            default:
507	                break;
508	        }
509	        self.checkingView.items = [NSArray arrayWithArray:self.items];
510	    } error:^(NSError * _Nullable error) {
511	        @strongify(self);
512	        [self updateView];
513	        
514	        if(error.code == XPKeyCheckErrorCodeCancel){
515	            [self.navigationController popViewControllerAnimated:YES];
516	            return;
517	        }
518	        
519	        if(error.code == XPKeyCheckErrorCodeGoToFinal){
520	            [XPStatisticsMgr sendEvent:XP_MOBILE_KEY_CHECK_FINAL module:XP_MOBILE_KEY_CHECK_MODULE data:@{@"sessionid": @(self.sessionId)}];
521	            
522	            self.finalView.hidden = NO;
523	            self.failView.hidden = YES;
524	            self.checkingView.hidden = YES;
525	            self.successView.hidden = YES;
526	            return;
527	        }
528	        
529	        self.currentError = error;
530	        NSString *title = error.userInfo[@"title"];
531	        if(title.length == 0){
532	            if(self.command == XPTBoxCommandUnlock){
533	                if(self.isStart){
534	                    title = @"启动失败";
535	                }else{
536	                    title = @"解锁失败";
537	                }
538	            }else{
539	                title = @"闭锁失败";
540	            }
541	        }
542	        self.failView.titleLabel.text = title;
543	        self.failView.subtitleLabel.text = error.localizedFailureReason;
544	        
545	        NSString *nextButtonTitle = @"重试";
546	        switch (error.code) {
547	            case XPKeyCheckErrorCodePoweredOff:
