730	- (RACCommand *)checkCommand{
731	    if(!_checkCommand){
732	        @weakify(self);
733	        _checkCommand = [[RACCommand alloc] initWithSignalBlock:^RACSignal * _Nonnull(id  _Nullable input) {
734	            @strongify(self);
735	            BOOL isResume = [input[@"resume"] boolValue];
736	            BOOL skipAlert = [input[@"skipAlert"] boolValue];
737	            NSInteger tryCount = isResume?0:2;
738	            
739	            //mona从哪里来都要询问远程
740	            if (CTMediator.isMona) {
741	                skipAlert = NO;
742	            }
743	            
744	            RACSignal *checkStateSignal = [[[self checkBleKeySignal] concat:[self checkRemoteSignalWithSkipAlert:skipAlert]] concat:[self checkBleStateSignalWithTimeout:isResume?5:2]];
745	            
746	            RACSignal *checkConnectSignal = [[[self checkNearbySignalWithTryCount:tryCount] concat:[self checkConnectSignalWithTryCount:tryCount]] concat:[self sendCommandSignalWithTryCount:tryCount]];
747	            
748	            if(CTMediator.isMona){
749	                checkConnectSignal = [[self monaCheckConnectSignalWithTryCount:tryCount] concat:[self sendMonaCommandSignalWithTryCount:tryCount tryDelete:NO]];
750	            }
751	            RACSignal *resultSignal = [[[RACSignal return:@(XPKeyCheckProgressDefault)] concat:checkStateSignal] concat:checkConnectSignal];
752	            if(isResume){
753	                resultSignal = [[[[RACSignal return:@(XPKeyCheckProgressDefault)] concat:checkStateSignal] concat:@[
754	                    @(XPKeyCheckProgressResetBleChecking),
755	                    @(XPKeyCheckProgressResetBleChecked),
756	                    @(XPKeyCheckProgressRestartChecking),
757	                    @(XPKeyCheckProgressRestartChecked),
758	                ].rac_sequence.signal] concat:checkConnectSignal];
759	            }
760	            
761	            resultSignal = [resultSignal catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
762	                @strongify(self);
763	                if(error.code == XPKeyCheckErrorCodeRemoteStarted || error.code == XPKeyCheckErrorCodeRemoteLocked){
764	                    self.isRemoteComplete = YES;
765	                    return RACSignal.empty;
766	                }
767	                return [RACSignal error:error];
768	            }];
769	            
770	            return [resultSignal takeUntil:self.rac_willDeallocSignal error:[NSError errorWithDomain:XPKeyCheckErrorDomain code:XPKeyCheckErrorCodeCancel userInfo:@{}]];
771	        }];
772	    }
773	    return _checkCommand;
774	}
